mapper.select:
SELECT ss.SEQ AS seq, ss.subject, DATE_FORMAT(ss.created_at, '%Y-%m-%d %H:%i') AS createdAt, DATE_FORMAT(ss.updated_at, '%Y-%m-%d %H:%i') AS updatedAt, DATE_FORMAT(ss.deleted_at, '%Y-%m-%d %H:%i') AS deletedAt, DATE_FORMAT(ss.trashed_at, '%Y-%m-%d %H:%i') AS trashedAt, ss.click_least_once AS clickLeastOnce, ( SELECT COUNT(s.SEQ) FROM TB_CS_TTS s WHERE s.seq > 0 AND s.created_at BETWEEN STR_TO_DATE(#{searchStartDate}, '%Y-%m-%d') AND DATE_ADD(#{searchEndDate}, INTERVAL 1 DAY)
AND s.deleted_at IS NULL AND s.trashed_at IS NULL
AND s.deleted_at IS NULL AND s.trashed_at IS NOT NULL
AND (s.subject LIKE CONCAT('%', #{keyword}, '%'))
AND s.seq = #{seq}
) AS hiddenCount, ( SELECT SUM(ctk.time_duration_ms) FROM TB_CS_TTS_KEYWORD ctk WHERE ctk.tts_seq = ss.seq ) AS timeDurationFormatted, ( SELECT AVG(ctk.reliability) FROM TB_CS_TTS_KEYWORD ctk WHERE ctk.tts_seq = ss.seq ) AS reliability, ( SELECT COUNT(*) FROM TB_CS_TRANSCRIPTION ctr JOIN TB_CS_TTS_KEYWORD ctk ON ctr.tts_seq = ctk.SEQ WHERE ctr.train_text IS NOT NULL AND ctr.train_text != '' AND ctk.tts_seq = ss.seq ) AS trainTextCount FROM TB_CS_TTS ss WHERE ss.seq > 0 AND ss.created_at BETWEEN STR_TO_DATE(#{searchStartDate}, '%Y-%m-%d') AND DATE_ADD(#{searchEndDate}, INTERVAL 1 DAY)
AND ss.deleted_at IS NULL AND ss.trashed_at IS NULL
AND ss.deleted_at IS NULL AND ss.trashed_at IS NOT NULL
AND (ss.subject LIKE CONCAT('%', #{keyword}, '%'))
AND ss.seq = #{seq}
ORDER BY ss.created_at DESC
LIMIT #{offsetPageable.offset}, #{offsetPageable.pageSize}

mapper.update:
update TB_CS_TTS
set click_least_once = 1
where seq = #{seq}
